#include <cstdio>
#include <omp.h>

#define NX 1024
#define NY 1024
#define NZ 1024
#define BLOCK_SIZE 32

__host__ void iso2dfd(float* __restrict__ p, float* __restrict__ a, int nx, int ny, int nz) {
  // Assuming p, a are allocated with nx*ny*nz elements
  // Using 7-point stencil as an example, similar to 2D 5-point stencil extended in z

  #pragma omp target teams distribute parallel for collapse(3) map(to: a[0:nx*ny*nz]) map(tofrom: p[0:nx*ny*nz])
  for (int k = 1; k < nz-1; ++k) {
    for (int j = 1; j < ny-1; ++j) {
      for (int i = 1; i < nx-1; ++i) {
        int idx = i + j * nx + k * nx * ny;
        float val = 0.f;

        val += a[idx] * p[idx];

        val += a[idx] * (p[idx+1] + p[idx-1] + p[idx+nx] + p[idx-nx] + p[idx+nx*ny] + p[idx-nx*ny] - 6.f * p[idx]);

        p[idx] = val;
      }
    }
  }
}

int main() {
  const int nx = NX;
  const int ny = NY;
  const int nz = NZ;

  float* p = new float[nx * ny * nz];
  float* a = new float[nx * ny * nz];

  // Initialize p and a with some values
  for (int i = 0; i < nx * ny * nz; ++i) {
    p[i] = 1.0f;
    a[i] = 1.0f;
  }

  iso2dfd(p, a, nx, ny, nz);

  // Print a single element to verify output
  printf("p[%d] = %f\n", (nx/2) + (ny/2)*nx + (nz/2)*nx*ny, p[(nx/2) + (ny/2)*nx + (nz/2)*nx*ny]);

  delete[] p;
  delete[] a;

  return 0;
}
